class Solution:
    def differenceOfSum(self, nums):
        element_sum = 0
        digit_sum = 0
        for x in nums:
            element_sum += x
            n = x
            while n > 0:
                digit_sum += n % 10
                n //= 10
        return abs(element_sum - digit_sum)

