var differenceOfSum = function(nums) {
    let elementSum = 0;
    let digitSum = 0;
    for (const x of nums) {
        elementSum += x;
        let n = x;
        while (n > 0) {
            digitSum += n % 10;
            n = Math.floor(n / 10);
        }
    }
    return Math.abs(elementSum - digitSum);
};
